sections.example:
unordered_set<string> words;
auto [it, inserted] = words.insert("hello");
cout << inserted << endl;  // 1 (true)

auto [it2, inserted2] = words.insert("hello");
cout << inserted2 << endl;  // 0 (false, already exists)

words.insert("world");
words.erase("hello");
cout << words.size() << endl;  // 1
cout << words.count("world") << endl;  // 1

