sections.example:
vector<int> nums = {4, 2, 7, 2, 4, 1, 7};
unordered_set<int> seen;
vector<int> unique_nums;
for (int x : nums) {
    if (seen.count(x) == 0) {
        seen.insert(x);
        unique_nums.push_back(x);
    }
}
for (int x : unique_nums) cout << x << " ";
// Output: 4 2 7 1  (original order preserved)

