    vector<int> nums = {5, 3, 5, 1, 3, 2, 1};
    unordered_set<int> seen;
    vector<int> result;
    for (int x : nums) {
        if (seen.(x) == 0) {
            seen.(x);
            result.push_back(x);
        }
    }
    for (int x : result) {
        cout << x << " ";
    }
    cout << endl;
    return 0;
}
